## 5. GraphQL 스키마 초안

graphql-skill 컨벤션(PascalCase 타입, `{Action}{Domain}Input` 패턴, `extend type Query/Mutation`)을 준수합니다.

```graphql
# ─── 공통 스칼라 ───
scalar DateTime

# ─── User 도메인 ───
type User {
    id: ID!
    nickname: String!
    gender: Int!
    birthYear: Int!
    status: Int!
    profile: UserProfile
    mannerScore: Float
    isFollowing: Boolean
    createdAt: DateTime!
}

type UserProfile {
    userId: ID!
    bio: String
    profileImageUrl: String
    voiceSampleUrl: String
    tags: [String!]!
    mbti: String
    location: String
    ageVisible: Boolean!
}

input UpdateUserProfileInput {
    bio: String
    profileImageUrl: String
    voiceSampleUrl: String
    tags: [String!]
    mbti: String
    location: String
    ageVisible: Boolean
}

extend type Query {
    me: User!
    user(userId: ID!): User
    users(limit: Int, offset: Int): [User!]!
}

extend type Mutation {
    updateUserProfile(input: UpdateUserProfileInput!): UserProfile!
    deleteAccount: Boolean!
}

# ─── Match 도메인 ───
type Match {
    id: ID!
    requester: User!
    receiver: User!
    status: Int!           # 0=대기 1=수락 2=거절 3=만료
    createdAt: DateTime!
    respondedAt: DateTime
}

input CreateMatchInput {
    receiverId: ID!
}

extend type Query {
    myMatches(status: Int, limit: Int, offset: Int): [Match!]!
}

extend type Mutation {
    createMatch(input: CreateMatchInput!): Match!
    respondMatch(matchId: ID!, accept: Boolean!): Match!
}

# ─── Call 도메인 ───
type Call {
    id: ID!
    roomId: String!
    callType: Int!
    status: Int!
    durationSeconds: Int!
    participants: [CallParticipant!]!
    startedAt: DateTime!
    endedAt: DateTime
}

type CallParticipant {
    userId: ID!
    user: User!
    role: Int!
    joinedAt: DateTime!
    leftAt: DateTime
}

input CreateCallInput {
    callType: Int!
    targetUserId: ID        # 1:1 통화 시 필수
}

input RateCallInput {
    callId: ID!
    targetUserId: ID!
    score: Int!             # 1~5
}

extend type Query {
    call(callId: ID!): Call
    myCallHistory(limit: Int, offset: Int): [Call!]!
}

extend type Mutation {
    createCall(input: CreateCallInput!): Call!
    endCall(callId: ID!): Call!
    rateCall(input: RateCallInput!): Boolean!
}

# ─── Follow 도메인 ───
type FollowConnection {
    followers: [User!]!
    followings: [User!]!
    followerCount: Int!
    followingCount: Int!
}

extend type Query {
    followInfo(userId: ID!): FollowConnection!
}

extend type Mutation {
    follow(targetUserId: ID!): Boolean!
    unfollow(targetUserId: ID!): Boolean!
}

# ─── Post 도메인 ───
type Post {
    id: ID!
    author: User!
    content: String!
    mediaUrl: String
    postType: Int!
    visibility: Int!
    likeCount: Int!
    commentCount: Int!
    isLiked: Boolean!
    createdAt: DateTime!
    updatedAt: DateTime!
}

type Comment {
    id: ID!
    postId: ID!
    author: User!
    content: String!
    createdAt: DateTime!
}

input CreatePostInput {
    content: String!
    mediaUrl: String
    postType: Int!
    visibility: Int!
}

input CreateCommentInput {
    postId: ID!
    content: String!
}

extend type Query {
    feed(limit: Int, offset: Int): [Post!]!
    post(postId: ID!): Post
    comments(postId: ID!, limit: Int, offset: Int): [Comment!]!
}

extend type Mutation {
    createPost(input: CreatePostInput!): Post!
    deletePost(postId: ID!): Boolean!
    createComment(input: CreateCommentInput!): Comment!
    deleteComment(commentId: ID!): Boolean!
    likePost(postId: ID!): Boolean!
    unlikePost(postId: ID!): Boolean!
}

# ─── Chat 도메인 ───
type ChatRoom {
    id: ID!
    matchId: ID!
    partner: User!
    lastMessageAt: DateTime
    createdAt: DateTime!
}

type ChatMessage {
    id: ID!
    chatRoomId: ID!
    sender: User!
    messageType: Int!
    content: String!
    readAt: DateTime
    createdAt: DateTime!
}

extend type Query {
    myChatRooms(limit: Int, offset: Int): [ChatRoom!]!
    chatMessages(chatRoomId: ID!, limit: Int, nextToken: String): ChatMessagePage!
