extend type Mutation {
    sendMessage(chatRoomId: ID!, content: String!, messageType: Int!): ChatMessage!
}

# ─── Notification 도메인 ───
type Notification {
    id: ID!
    type: String!
    title: String!
    body: String!
    isRead: Boolean!
    targetId: String
